-- Name: generate_order_code(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_order_code() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF NEW.order_code IS NULL OR NEW.order_code = '' THEN
        NEW.order_code = 'ORD-' || TO_CHAR(CURRENT_DATE, 'YYYYMMDD') || '-' || LPAD(FLOOR(RANDOM() * 1000000)::TEXT, 6, '0');
    END IF;
    RETURN NEW;
END;
$$;


--
-- TOC entry 261 (class 1255 OID 19224)
-- Name: generate_product_code(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_product_code() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    prefix VARCHAR(3);
BEGIN
    IF NEW.product_code IS NULL OR NEW.product_code = '' THEN
        prefix = UPPER(LEFT(REGEXP_REPLACE(NEW.name, '[^a-zA-Z]', '', 'g'), 3));
        IF LENGTH(prefix) < 3 THEN
            prefix = RPAD(prefix, 3, 'X');
        END IF;
        NEW. product_code = prefix || '-' || LPAD(FLOOR(RANDOM() * 100000000)::TEXT, 8, '0');
    END IF;
    RETURN NEW;
END;
$$;


